const crypto = require('crypto');
const body = $input.first().json.body || {};
const sig = $input.first().json.headers?.['x-hub-signature-256'];
if (sig) {
  const expected = 'sha256=' + crypto.createHmac('sha256', process.env.N8N_SHARED_SECRET || '').update(JSON.stringify(body)).digest('hex');
  if (sig !== expected) throw new Error('HMAC validation failed');
}
return [{ json: { client_id: body.client_id, week_start: body.week_start, research_run_id: body.research_run_id } }];

let scripts;
try {
  const raw = $input.first().json.content[0].text;
  const parsed = JSON.parse(raw);
  scripts = parsed.scripts;
} catch(e) {
  throw new Error('Claude returned invalid JSON: ' + e.message);
}

if (!Array.isArray(scripts) || scripts.length !== 5) throw new Error('Expected exactly 5 scripts, got: ' + (scripts?.length || 0));

const required = ['idx','topic','hook','beats','cta','caption','hashtags','compliance'];
for (const script of scripts) {
  for (const field of required) {
    if (script[field] === undefined) throw new Error(`Script ${script.idx}: missing field '${field}'`);
  }
  if (!Array.isArray(script.beats) || script.beats.length < 3) throw new Error(`Script ${script.idx}: beats must have ≥3 items`);
  if (!script.cta.spoken || !script.cta.on_screen || !script.cta.dm_prompt) throw new Error(`Script ${script.idx}: cta missing fields`);
}

return [{ json: { scripts, valid: true } }];

const { scripts } = $input.first().json;
const flagged = scripts.filter(s => s.compliance?.risk_flags?.length > 0);
const clean = scripts.filter(s => !s.compliance?.risk_flags?.length);

// In production: loop over flagged scripts, call Claude API with compliance-rewrite-v1.md
// For now: mark flagged scripts for separate compliance-rewrite HTTP calls
return [{ json: { all_scripts: scripts, flagged_count: flagged.length, flagged_idx: flagged.map(s => s.idx) } }];

const { all_scripts } = $input.first().json;
const batchId = $('Insert script_batch').item.json[0]?.script_batch_id;
const clientId = $('Validate HMAC + Fetch Data').item.json.client_id;
const weekStart = $('Validate HMAC + Fetch Data').item.json.week_start;

return all_scripts.map(s => ({
  json: {
    client_id: clientId,
    script_batch_id: batchId,
    week_start: weekStart,
    idx: s.idx,
    status: 'pending_approval',
    script_json: s,
    approval_attempt: 1
  }
}));

// Format all 5 scripts into one Telegram message with inline keyboard
const scripts = $('Insert scripts to Supabase').all().map(i => i.json);
const savedScripts = $('POST scripts to Supabase').all().map(i => i.json[0] || i.json);
const batchId = savedScripts[0]?.script_batch_id || 'unknown';

let text = `📋 *Week Scripts Ready — ${savedScripts[0]?.week_start}*\n`;
text += `Client: ${savedScripts[0]?.client_id}\n\n`;

for (const s of scripts) {
  const sc = s.script_json || s;
  text += `*Script ${sc.idx}: ${sc.topic}*\n`;
  text += `Hook: "${sc.hook}"\n`;
  text += `Beats: ${sc.beats?.length || 0} | Duration: ~40s\n`;
  text += `CTA: "${sc.cta?.spoken}"\n`;
  text += `Risk flags: ${sc.compliance?.risk_flags?.length > 0 ? sc.compliance.risk_flags.join(', ') : 'None'}\n\n`;
}

const inlineKeyboard = {
  inline_keyboard: [
    [{ text: '✅ Approve All', callback_data: `approve_all:${batchId}` }],
    [{ text: '✏️ Request Revision', callback_data: `reject_all:${batchId}` }]
  ]
};

return [{ json: { text, reply_markup: JSON.stringify(inlineKeyboard) } }];
